<script setup lang="ts">
import { useSettingsStore } from '../../stores/settingsStore'
import { useLibraryStore } from '../../stores/libraryStore'
import { useCastStore } from '../../stores/castStore'
import { runCastDoctor } from '../../api/cast'
import { useAppStore } from '../../stores/appStore'

const settings = useSettingsStore(); const library = useLibraryStore(); const cast = useCastStore(); const app = useAppStore()
async function runDoctor() { try { await runCastDoctor(); await cast.loadDoctor(); app.toast('Cast Doctor completed', 'success'); app.setSection('diagnostics') } catch (err) { app.toast(err instanceof Error ? err.message : 'Cast Doctor failed', 'error') } }
function save() { settings.theme = 'light'; settings.persist(); cast.setBackend(settings.defaultCastBackend); library.setViewMode(settings.defaultView); app.toast('Settings saved', 'success') }
function reset() { if (!confirm('Reset Cast Manager preferences in this browser? Server data will not be changed.')) return; settings.resetLocal(); library.setViewMode('list'); cast.setBackend('auto'); app.toast('Local preferences reset', 'success') }
</script>
<template><section class="page-stack" data-testid="settings-page"><div class="page-actions"><div><span class="eyebrow">Preferences</span><h1 class="page-title">Settings</h1><p class="page-description">Clear, local defaults for this browser. The server media root is read-only here.</p></div><button class="btn btn-primary" @click="save">Save settings</button></div><div class="diagnostics-layout"><article class="card"><span class="eyebrow">Appearance</span><h2 class="card-title">Interface</h2><div class="field"><label for="theme">Theme</label><select id="theme" v-model="settings.theme" class="select"><option value="light">Light</option><option disabled value="dark">Dark (not available yet)</option></select><span class="field-help">Light is the reliable default. Dark mode can be added later without changing core workflows.</span></div><div class="field" style="margin-top:16px"><label for="default-view">Default Library view</label><select id="default-view" v-model="settings.defaultView" class="select"><option value="list">List</option><option value="grid">Grid</option></select></div><div class="field" style="margin-top:16px"><label for="media-root">Default media root</label><input id="media-root" class="input mono" :value="library.mediaRoot" readonly /><span class="field-help">Provided by GET /api/config; fallback is /home/REDACTED_USER/watch_list.</span></div></article><article class="card"><span class="eyebrow">Casting</span><h2 class="card-title">Playback defaults</h2><div class="field"><label for="device">Selected device</label><select id="device" class="select" :disabled="!cast.devices.length" @change="cast.pickDevice(cast.devices[($event.target as HTMLSelectElement).selectedIndex])"><option v-if="!cast.devices.length">No devices discovered</option><option v-for="device in cast.devices" :key="device.deviceId" :selected="device.selected">{{ device.name }} · {{ device.provider }}</option></select><button class="btn btn-secondary btn-sm" style="margin-top:8px;align-self:flex-start" @click="cast.scanDevices()">Refresh devices</button></div><div class="field" style="margin-top:16px"><label for="backend">Default cast backend</label><select id="backend" v-model="settings.defaultCastBackend" class="select"><option value="auto">Auto (recommended)</option><option value="direct">Direct</option><option value="ffmpeg-live">FFmpeg live</option><option value="vlc">VLC</option><option v-if="library.config?.features?.hls" value="hls">HLS</option><option v-if="settings.allowPretranscode" value="pretranscode">Pretranscode</option></select></div><label style="margin-top:16px"><input v-model="settings.autoTranscode" type="checkbox" /> Allow automatic transcoding when direct playback is incompatible</label><label><input v-model="settings.allowPretranscode" type="checkbox" /> Allow pretranscode backend (advanced)</label></article></div><article class="card"><span class="eyebrow">Support</span><h2 class="card-title">Diagnostics</h2><div class="diagnostics-layout"><div class="field"><label for="verbosity">Diagnostics verbosity</label><select id="verbosity" v-model="settings.diagnosticsVerbosity" class="select"><option value="quiet">Quiet</option><option value="normal">Normal</option><option value="verbose">Verbose</option></select></div><div><p style="color:var(--text-muted)">Cast Doctor checks device discovery, media tooling, backend availability, and stream prerequisites.</p><button class="btn btn-secondary" @click="runDoctor">Run Cast Doctor</button></div></div></article><div class="button-row"><button class="btn btn-primary" @click="save">Save settings</button><button class="btn btn-danger" @click="reset">Reset local preferences</button></div></section></template>
